import json
import sqlite3
from pathlib import Path


class KeyValueMemory:
    """
    Simple persistent key-value store backed by SQLite.
    Survives process restarts and is accessible across agent runs.
    """

    def __init__(self, path: str = "agent_memory.db"):
        self.conn = sqlite3.connect(path)
        self.conn.execute(
            "CREATE TABLE IF NOT EXISTS kv (key TEXT PRIMARY KEY, value TEXT)"
        )
        self.conn.commit()

    def set(self, key: str, value: object) -> None:
        self.conn.execute(
            "INSERT OR REPLACE INTO kv (key, value) VALUES (?, ?)",
            (key, json.dumps(value)),
        )
        self.conn.commit()

    def get(self, key: str, default=None) -> object:
        row = self.conn.execute(
            "SELECT value FROM kv WHERE key = ?", (key,)
        ).fetchone()
        if row is None:
            return default
        return json.loads(row[0])

    def delete(self, key: str) -> None:
        self.conn.execute("DELETE FROM kv WHERE key = ?", (key,))
        self.conn.commit()


# Usage in an agent run:
memory = KeyValueMemory("runs/memory.db")

# Save what was discovered in this run
memory.set("last_run", {
    "files_read": ["auth.py", "session.py"],
    "bug_found": "auth.py:42 — password not URL-decoded",
    "status": "fix_applied",
})

# Next run reads it
last = memory.get("last_run")
if last and last["status"] == "fix_applied":
    print("Previous run applied a fix. Verify tests pass.")

import anthropic

client = anthropic.Anthropic()


def run_with_memory(task: str, memory: KeyValueMemory, store: DocumentStore) -> str:
    """
    Agent loop that reads from long-term memory at the start and writes to it
    at the end. Short-term memory (messages list) is used during the run;
    long-term memory persists the outcome.
    """
    # --- Load from long-term memory ---
    run_id = f"run-{int(time.time())}"
    last_run = memory.get("last_run")
    context = ""
    if last_run:
        context = (
            f"Previous run status: {last_run['status']}\n"
            f"Files modified: {last_run.get('files_modified', [])}\n"
        )

    # --- Short-term memory: messages list ---
    messages = [{"role": "user", "content": context + task if context else task}]

    for step in range(30):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            result = next(
                (b.text for b in response.content if hasattr(b, "text")), ""
            )
            # --- Write to long-term memory ---
            memory.set("last_run", {
                "run_id": run_id,
                "status": "done",
                "files_modified": _extract_modified_files(messages),
            })
            store.save(run_id, {"task": task, "result": result})
            return result

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": dispatch_tool(block.name, block.input),
                })
        messages.append({"role": "user", "content": tool_results})

    return "Max steps reached."


def _extract_modified_files(messages: list[dict]) -> list[str]:
    """Extract file paths from write_file tool calls in the messages list."""
    files = []
    for m in messages:
        if m["role"] == "assistant":
            for block in (m["content"] if isinstance(m["content"], list) else []):
                if hasattr(block, "name") and block.name == "write_file":
                    files.append(block.input.get("path", ""))
    return files

# Long-term memory enables deduplication across multiple runs.
# Without it, a multi-run agent may process the same item twice.

class ProcessedSet:
    """
    Persistent set of processed item IDs.
    Backed by SQLite; survives across runs and process restarts.
    """

    def __init__(self, memory: KeyValueMemory, key: str = "processed_ids"):
        self.memory = memory
        self.key = key

    def _load(self) -> set[str]:
        return set(self.memory.get(self.key, []))

    def _save(self, ids: set[str]) -> None:
        self.memory.set(self.key, list(ids))

    def mark_done(self, item_id: str) -> None:
        ids = self._load()
        ids.add(item_id)
        self._save(ids)

    def is_done(self, item_id: str) -> bool:
        return item_id in self._load()

    def count(self) -> int:
        return len(self._load())


# Usage:
processed = ProcessedSet(memory)
items = ["issue-1", "issue-2", "issue-3"]

for item_id in items:
    if processed.is_done(item_id):
        print(f"Skip {item_id} — already processed")
        continue
    # process the item...
    processed.mark_done(item_id)

import pytest
import tempfile
import os


class TestKeyValueMemory:
    def test_set_and_get(self, tmp_path):
        mem = KeyValueMemory(str(tmp_path / "test.db"))
        mem.set("key1", {"a": 1})
        assert mem.get("key1") == {"a": 1}

    def test_get_missing_returns_default(self, tmp_path):
        mem = KeyValueMemory(str(tmp_path / "test.db"))
        assert mem.get("missing", "default") == "default"

    def test_delete_removes_key(self, tmp_path):
        mem = KeyValueMemory(str(tmp_path / "test.db"))
        mem.set("key1", 42)
        mem.delete("key1")
        assert mem.get("key1") is None

    def test_set_overwrites(self, tmp_path):
        mem = KeyValueMemory(str(tmp_path / "test.db"))
        mem.set("key1", "first")
        mem.set("key1", "second")
        assert mem.get("key1") == "second"


class TestDocumentStore:
    def test_save_and_load(self, tmp_path):
        store = DocumentStore(str(tmp_path))
        store.save("doc1", {"x": 10})
        loaded = store.load("doc1")
        assert loaded == {"x": 10}

    def test_load_missing_returns_none(self, tmp_path):
        store = DocumentStore(str(tmp_path))
        assert store.load("nonexistent") is None

    def test_list_ids(self, tmp_path):
        store = DocumentStore(str(tmp_path))
        store.save("a", {})
        store.save("b", {})
        assert set(store.list_ids()) == {"a", "b"}


class TestProcessedSet:
    def test_mark_and_check(self, tmp_path):
        mem = KeyValueMemory(str(tmp_path / "test.db"))
        ps = ProcessedSet(mem)
        assert not ps.is_done("item-1")
        ps.mark_done("item-1")
        assert ps.is_done("item-1")

    def test_count(self, tmp_path):
        mem = KeyValueMemory(str(tmp_path / "test.db"))
        ps = ProcessedSet(mem)
        ps.mark_done("a")
        ps.mark_done("b")
        assert ps.count() == 2
